import{_ as a,o as n,c as t,ag as r}from"./chunks/framework._658-eYr.js";const i="/CRAFT/assets/create-channel.2CRGc_04.png",p=JSON.parse('{"title":"Channels","description":"","frontmatter":{},"headers":[],"relativePath":"guide/channels.md","filePath":"guide/channels.md"}'),s={name:"guide/channels.md"};function o(l,e,c,h,d,g){return n(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="channels" tabindex="-1">Channels <a class="header-anchor" href="#channels" aria-label="Permalink to &quot;Channels&quot;">​</a></h1><p>Channels are the top-level organizer in CRAFT. Each channel has its own character personality, topics, voice settings, and content library.</p><h2 id="creating-a-channel" tabindex="-1">Creating a Channel <a class="header-anchor" href="#creating-a-channel" aria-label="Permalink to &quot;Creating a Channel&quot;">​</a></h2><ol><li>Click <strong>+ Add Channel</strong> in the sidebar</li><li>Enter a <strong>Channel Name</strong> (e.g., &quot;Tech Explained&quot;)</li><li>Enter a <strong>Character Name</strong> (your on-screen persona, e.g., &quot;Alex&quot;)</li><li>Click <strong>Create</strong></li></ol><p><img src="'+i+'" alt="Create Channel"></p><h2 id="channel-settings" tabindex="-1">Channel Settings <a class="header-anchor" href="#channel-settings" aria-label="Permalink to &quot;Channel Settings&quot;">​</a></h2><p>Click the <strong>gear icon</strong> that appears when hovering over a channel in the sidebar.</p><h3 id="character" tabindex="-1">Character <a class="header-anchor" href="#character" aria-label="Permalink to &quot;Character&quot;">​</a></h3><ul><li><strong>Name</strong> — your character&#39;s display name</li><li><strong>Description</strong> — personality, tone, speaking style. This is fed to the AI for all content generation.</li><li><strong>Topics</strong> — content themes (e.g., &quot;cloud computing&quot;, &quot;DevOps&quot;, &quot;terraform&quot;). Used as default search hints in Discover.</li><li><strong>Tags</strong> — organizational labels for your ideas and scripts</li></ul><div class="tip custom-block"><p class="custom-block-title">AI Character Creator</p><p>Click <strong>Create Character</strong> in Settings to have AI generate a full character description from a few inputs: tone, audience, inspiration, and quirks.</p></div><h3 id="voice" tabindex="-1">Voice <a class="header-anchor" href="#voice" aria-label="Permalink to &quot;Voice&quot;">​</a></h3><p>Configure a default TTS voice for audio generation:</p><ul><li><strong>Service</strong> — Edge TTS (free), ElevenLabs, or OpenAI</li><li><strong>Voice</strong> — cascading filters by language, gender, then specific voice</li><li><strong>Test</strong> — preview the voice before saving</li></ul><h3 id="analytics" tabindex="-1">Analytics <a class="header-anchor" href="#analytics" aria-label="Permalink to &quot;Analytics&quot;">​</a></h3><ul><li><strong>RPM</strong> — Revenue Per Mille (per 1,000 views). Used for earnings estimates in Discover.</li><li><strong>Niche Presets</strong> — quick-select RPM values (Gaming $3, Tech $6, Finance $10, etc.)</li></ul><h3 id="claude-md" tabindex="-1">CLAUDE.md <a class="header-anchor" href="#claude-md" aria-label="Permalink to &quot;CLAUDE.md&quot;">​</a></h3><p>The AI Context editor lets you view and edit the CLAUDE.md file that shapes Claude&#39;s responses for this channel. In <strong>Character</strong> mode, it&#39;s auto-generated from your settings. In <strong>Raw</strong> mode, you can write custom instructions.</p><h2 id="switching-channels" tabindex="-1">Switching Channels <a class="header-anchor" href="#switching-channels" aria-label="Permalink to &quot;Switching Channels&quot;">​</a></h2><p>Click any channel in the sidebar to switch. All panels (Ideas, Scripts, Discover, etc.) update to show that channel&#39;s content.</p><h2 id="multiple-channels" tabindex="-1">Multiple Channels <a class="header-anchor" href="#multiple-channels" aria-label="Permalink to &quot;Multiple Channels&quot;">​</a></h2><p>You can create as many channels as you need — one per YouTube channel, or separate ones for different content series.</p>',21)])])}const m=a(s,[["render",o]]);export{p as __pageData,m as default};
